// ================================================================
// Node: Extract Transaction Data from Jago Email (V5 - Brute Force)
// ================================================================

const item = $input.first();
const subject = item.json.subject || '';
const snippet = item.json.snippet || '';

// --- 1. Robust recursive decoding ---
const decodeB64 = (str) => {
  if (!str) return '';
  try {
    const base64 = str.replace(/-/g, '+').replace(/_/g, '/');
    return Buffer.from(base64, 'base64').toString('utf-8');
  } catch (e) { return ''; }
};

const getGmailText = (payload) => {
  let results = [];
  if (payload.body && payload.body.data) results.push(decodeB64(payload.body.data));
  if (payload.parts) payload.parts.forEach(p => results.push(getGmailText(p)));
  return results.join(' ');
};

const payloadText = getGmailText(item.json.payload || item.json);
const htmlText    = item.json.textHtml || item.json.html || '';
const plainText   = item.json.textPlain || item.json.text || '';

// Combine everything for maximum visibility
let combined = [subject, snippet, htmlText, plainText, payloadText].join(' ');

// Normalize text (remove HTML, entities, and extra spaces)
let cleanText = combined
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<[^>]+>/g, ' ')
  .replace(/[&][a-z0-9#]+;/gi, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// --- 2. Brute Force Nominal Search ---
const priceRegex = /(?:Jumlah|Total|Rp|IDR)\s*[:\-\.]?\s*(?:Rp\.?|IDR)?\s*([\d.,]{3,})/gi;
let nominal = 0;
let matches;
let foundPrices = [];

while ((matches = priceRegex.exec(cleanText)) !== null) {
  let numStr = matches[1];
  if (numStr.includes(',') && numStr.includes('.')) {
    numStr = numStr.replace(/\./g, '').replace(',', '.');
  } else if (numStr.includes(',')) {
    numStr = numStr.replace(/,/g, '.');
  } else {
    numStr = numStr.replace(/\./g, '');
  }
  const val = parseFloat(numStr);
  if (!isNaN(val) && val > 0) foundPrices.push(val);
}

// Use the first valid price found (usually the transaction amount in Jago emails)
if (foundPrices.length > 0) nominal = foundPrices[0];

// --- 3. Date extraction ---
const dateMatch = cleanText.match(/(\d{1,2})\s+(Jan|Feb|Mar|Apr|Mei|May|Jun|Jul|Agt|Aug|Sep|Okt|Oct|Nov|Des|Dec)[a-z]*\s+(\d{4})/i);
const timeMatch = cleanText.match(/(\d{2}:\d{2})(?:\s*WIB)?/i);

const monthMap = {
  jan: '01', feb: '02', mar: '03', apr: '04', mei: '05', may: '05', 
  jun: '06', jul: '07', agt: '08', agu: '08', aug: '08', 
  sep: '09', okt: '10', oct: '10', nov: '11', des: '12', dec: '12'
};

let tanggalWaktu = new Date().toISOString();
if (dateMatch) {
  const day = dateMatch[1].padStart(2, '0');
  const mon = monthMap[dateMatch[2].toLowerCase().slice(0, 3)];
  const yr  = dateMatch[3];
  const hr  = timeMatch ? timeMatch[1] : '00:00';
  tanggalWaktu = `${yr}-${mon}-${day}T${hr}:00+07:00`;
}

// --- 4. Merchant extraction (Look for 'Ke' followed by name) ---
const merchantMatch = cleanText.match(/Ke\s*[:\.]?\s*([A-Z ]{3,30})/);
let merchant = merchantMatch ? merchantMatch[1].trim() : 'Unknown';

// --- Validation ---
if (nominal === 0) {
  throw new Error(`Harga tetap tidak ditemukan. Karakter terbaca: ${cleanText.length}. Awal teks: ${cleanText.slice(0, 100)}...`);
}

// LOGIKA TIPE: Sangat spesifik ke pola email Jago
let tipe = 'debit';
const isKredit = /Kamu menerima|Saldo kamu bertambah|Dana masuk|Transfer masuk|Top Up berhasil/i.test(subject);
const isDebit = /Kamu telah membayar|Kamu telah melakukan|Kamu mengirimkan|Kamu memindahkan/i.test(subject);

if (isKredit) tipe = 'kredit';
else if (isDebit) tipe = 'debit';
else {
  // Fallback ke body jika subject tidak jelas
  if (/kredit|penerimaan|terima transfer/i.test(cleanText) && !/membayar|mengirimkan|pembayaran/i.test(cleanText)) {
    tipe = 'kredit';
  }
}

return [{
  json: {
    tanggal_waktu: tanggalWaktu,
    tipe,
    nominal,
    merchant_deskripsi: merchant,
    kategori_otomatis: 'Lain-lain',
    email_subject: subject,
    debug_full_text: cleanText.slice(0, 1000)
  }
}];
